select:
SELECT bd.BILLING_DETAIL_ID AS billingDetailId, bd.BILLING_MASTER_ID AS billingMasterId, bd.SOURCE_SERVICE_CODE AS sourceServiceCode, bd.SOURCE_RECORD_ID AS sourceRecordId, bd.FEE_CODE AS feeCode, bd.ITEM_NAME AS itemName, bd.QUANTITY AS quantity, bd.UNIT_PRICE AS unitPrice, bd.AMOUNT AS amount, bd.DETAIL_STATUS AS detailStatus, bd.OCCURRED_AT AS occurredAt, bd.CREATED_AT AS createdAt, bd.UPDATED_AT AS updatedAt, bm.DEFAULT_PRICE AS defaultPrice
FROM BILLING_DETAIL bd, BILLING_MASTER bm
WHERE bd.BILLING_MASTER_ID = bm.BILLING_MASTER_ID
AND bd.BILLING_DETAIL_ID = #{billingDetailId}
AND bd.FEE_CODE = #{feeCode}
AND bd.DETAIL_STATUS = #{detailStatus}
ORDER BY bd.CREATED_AT DESC
